package exec.rpc.org.apache.drill.exec.rpc;

public abstract class AbstractHandshakeHandler < T extends MessageLite > extends MessageToMessageDecoder < InboundRpcMessage > { static final org . slf4j . Logger logger = org . slf4j . LoggerFactory . getLogger ( AbstractHandshakeHandler . class ) ; protected final EnumLite handshakeType ; protected final Parser < T > parser ; protected volatile int coordinationId ; public AbstractHandshakeHandler ( EnumLite handshakeType , Parser < T > parser ) { super ( ) ; this . handshakeType = handshakeType ; this . parser = parser ; } @ Override protected void decode ( ChannelHandlerContext ctx , InboundRpcMessage inbound , List < Object > outputs ) throws Exception { try { if ( RpcConstants . EXTRA_DEBUGGING ) { logger . debug ( "Received handshake {}" , inbound ) ; } this . coordinationId = inbound . coordinationId ; ctx . channel ( ) . pipeline ( ) . remove ( this ) ; if ( inbound . rpcType != handshakeType . getNumber ( ) ) { throw new RpcException ( String . format ( "Handshake failure.  Expected %s[%d] but received number [%d]" , handshakeType , handshakeType . getNumber ( ) , inbound . rpcType ) ) ; } T msg = parser . parseFrom ( inbound . getProtobufBodyAsIS ( ) ) ; consumeHandshake ( ctx , msg ) ; } finally { inbound . pBody . release ( ) ; if ( inbound . dBody != null ) { inbound . dBody . release ( ) ; } } } protected abstract void consumeHandshake ( ChannelHandlerContext ctx , T msg ) throws Exception ; }